sql:
SELECT COUNT(*) 
FROM economic_data 
WHERE sector_id = 1 AND region_id = 1;

SELECT year, MAX(ipcmag) AS max_ipcmag
FROM economic_data
GROUP BY year;

SELECT ipcmag
FROM economic_data
WHERE year = 0 AND region_id = 0;

SELECT year
FROM economic_data
WHERE ipcmag = (SELECT MAX(ipcmag) FROM economic_data);

SELECT year, sector_id, AVG(ipcmag) AS average_ipcmag
FROM economic_data
GROUP BY year, sector_id;

SELECT ipc1, ipc4
FROM economic_data
WHERE year = 0 AND region_id = 0 AND sector_id = 0 AND source_id = 1;

SELECT ipcmag
FROM economic_data
WHERE year = 1 AND sector_id = 1;

SELECT AVG(ipcmag) AS average_ipcmag
FROM economic_data
WHERE year = 1 AND region_id = 1;

SELECT year, region_id, COUNT(DISTINCT sector_id) AS sector_count
FROM economic_data
GROUP BY year, region_id;

SELECT SUM(ipcmag) AS total_ipcmag
FROM economic_data
WHERE year = 2023 AND sector_id = 1;
